    field :avatar_url, :string
    field :role, :string, default: "user"
    field :credits, :integer, default: 0
    field :verified_status, :string, default: "unverified"
    field :account_type, :string, default: "free"
    field :tenant_id, :integer

    timestamps()
  end

  @user_updatable_fields [:name, :email, :bio, :avatar_url]
  @admin_updatable_fields [:name, :email, :bio, :avatar_url, :role, :credits, :verified_status, :account_type]

  def update_changeset(user, params, :user) do
    user
    |> cast(params, @user_updatable_fields)
    |> validate_required([:name, :email])
    |> validate_format(:email, ~r/^[^\s]+@[^\s]+\.[^\s]+$/)
    |> validate_length(:name, min: 1, max: 255)
