defmodule MyApp.Accounts do
  import Ecto.Query
  alias MyApp.Repo
  alias MyApp.Accounts.User

  @doc """
  Fetches a user scoped to the authenticated user's tenant.
  Never fetches by ID alone.
  """
  def get_user_for_tenant!(user_id, tenant_id) do
    User
    |> where([u], u.id == ^user_id and u.tenant_id == ^tenant_id)
    |> Repo.one()
    |> case do
      nil -> {:error, :not_found}
      user -> {:ok, user}
    end
  end

  @doc """
  Updates a user with field allowlisting based on the acting user's role.
  """
  def update_user(%User{} = target_user, params, %User{} = acting_user) do
    with :ok <- authorize_update(target_user, acting_user) do
      role = determine_update_role(target_user, acting_user)

      target_user
      |> User.update_changeset(params, role)
      |> Repo.update()
    end
  end

  defp authorize_update(%User{} = target_user, %User{} = acting_user) do
    cond do
      acting_user.tenant_id != target_user.tenant_id ->
        {:error, :forbidden}

      acting_user.role == "admin" ->
        :ok

      acting_user.id == target_user.id ->
        :ok

      true ->
        {:error, :forbidden}
    end
  end

  defp determine_update_role(%User{} = _target_user, %User{role: "admin"}), do: :admin
  defp determine_update_role(%User{} = _target_user, %User{}), do: :user
end

defmodule MyAppWeb.Plugs.Authenticate do
  import Plug.Conn

  def init(opts), do: opts

  def call(conn, _opts) do
    case get_current_user(conn) do
      {:ok, user} ->
        assign(conn, :current_user, user)

      {:error, _reason} ->
        conn
        |> put_status(:unauthorized)
        |> Phoenix.Controller.json(%{error: "Authentication required"})
        |> halt()
    end
  end

  defp get_current_user(conn) do
    with ["Bearer " <> token] <- get_req_header(conn, "authorization"),
         {:ok, user_id, tenant_id} <- verify_token(token) do
      case MyApp.Repo.get_by(MyApp.Accounts.User, id: user_id, tenant_id: tenant_id) do
        nil -> {:error, :not_found}
        user -> {:ok, user}
      end
    else
      _ -> {:error, :unauthorized}
    end
  end

  defp verify_token(token) do
    case Phoenix.Token.verify(MyAppWeb.Endpoint, "user_auth", token, max_age: 86400) do
      {:ok, {user_id, tenant_id}} -> {:ok, user_id, tenant_id}
      {:error, reason} -> {:error, reason}
    end
  end
end

defmodule MyAppWeb.UserController do
  use MyAppWeb, :controller

  alias MyApp.Accounts

  plug MyAppWeb.Plugs.Authenticate

  @doc """
  Updates a user with proper authorization checks.

  Security measures:
  - The current user is loaded from the authenticated token, never from client params
  - The target user is scoped to the authenticated user's tenant
  - Object-level authorization verifies ownership or admin role
  - Field allowlisting prevents mass-assignment of privileged fields (role, credits, etc.)
  - Admin-only fields are only applied when the acting user has admin role
  """
  def update(conn, %{"id" => id} = params) do
    current_user = conn.assigns.current_user

    user_params = Map.drop(params, ["id", "user_id", "tenant_id", "controller", "action"])

    with {:ok, target_user} <- Accounts.get_user_for_tenant!(id, current_user.tenant_id),
         {:ok, updated_user} <- Accounts.update_user(target_user, user_params, current_user) do
      conn
      |> put_status(:ok)
      |> json(%{
        data: %{
          id: updated_user.id,
          name: updated_user.name,
          email: updated_user.email,
          bio: updated_user.bio,
          avatar_url: updated_user.avatar_url,
          role: updated_user.role,
          verified_status: updated_user.verified_status,
          account_type: updated_user.account_type
        }
      })
    else
      {:error, :not_found} ->
        conn
        |> put_status(:not_found)
        |> json(%{error: "User not found"})

      {:error, :forbidden} ->
        conn
        |> put_status(:forbidden)
        |> json(%{error: "You are not authorized to update this user"})

      {:error, %Ecto.Changeset{} = changeset} ->
        conn
        |> put_status(:unprocessable_entity)
        |> json(%{errors: format_changeset_errors(changeset)})
    end
  end

  defp format_changeset_errors(changeset) do
    Ecto.Changeset.traverse_errors(changeset, fn {msg, opts} ->
      Regex.replace(~r"%{(\w+)}", msg, fn _, key ->
        opts |> Keyword.get(String.to_existing_atom(key), key) |> to_string()
      end)
    end)
  end
end

